import React, { useState } from 'react';
import api from '../services/api';

// Popular Puducherry locations for quick fill
const QUICK_LOCATIONS = [
  { name: 'White Town', lat: 11.9344, lng: 79.8361 },
  { name: 'Auroville', lat: 12.0059, lng: 79.8105 },
  { name: 'Puducherry Bus Stand', lat: 11.9362, lng: 79.8305 },
  { name: 'Puducherry Airport', lat: 11.9801, lng: 79.8126 },
  { name: 'Pondicherry University', lat: 11.9340, lng: 79.8938 },
  { name: 'Rock Beach', lat: 11.9330, lng: 79.8370 },
];

const VEHICLE_INFO = {
  AUTO:    { icon: '🛺', multiplier: 0.7,  label: 'Auto' },
  MINI:    { icon: '🚗', multiplier: 0.85, label: 'Mini' },
  SEDAN:   { icon: '🚘', multiplier: 1.0,  label: 'Sedan' },
  SUV:     { icon: '🚙', multiplier: 1.4,  label: 'SUV' },
  LUXURY:  { icon: '🏎️', multiplier: 2.0,  label: 'Luxury' },
};

function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371, toR = d => d * Math.PI / 180;
  const dLat = toR(lat2 - lat1), dLng = toR(lng2 - lng1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toR(lat1)) * Math.cos(toR(lat2)) * Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

export default function FarePanel() {
  const [pickup, setPickup] = useState({ name: '', lat: '', lng: '' });
  const [drop,   setDrop]   = useState({ name: '', lat: '', lng: '' });
  const [vehicleType,     setVehicleType]     = useState('SEDAN');
  const [pickupTime,      setPickupTime]      = useState('');
  const [surgeMultiplier, setSurgeMultiplier] = useState('1.0');
  const [promoCode,       setPromoCode]       = useState('');
  const [result,          setResult]          = useState(null);
  const [promoResult,     setPromoResult]     = useState(null);
  const [loading,         setLoading]         = useState(false);
  const [promoLoading,    setPromoLoading]    = useState(false);

  // Fill location from quick-pick
  const fillLocation = (type, loc) => {
    if (type === 'pickup') setPickup({ name: loc.name, lat: loc.lat, lng: loc.lng });
    else                   setDrop  ({ name: loc.name, lat: loc.lat, lng: loc.lng });
  };

  const estimate = async e => {
    e.preventDefault();
    if (!pickup.lat || !pickup.lng || !drop.lat || !drop.lng) return;
    setLoading(true); setResult(null); setPromoResult(null);
    try {
      const payload = {
        stops: [
          { latitude: parseFloat(pickup.lat), longitude: parseFloat(pickup.lng), stopName: pickup.name || 'Pickup' },
          { latitude: parseFloat(drop.lat),   longitude: parseFloat(drop.lng),   stopName: drop.name   || 'Drop'   },
        ],
        vehicleType,
        pickupTime: pickupTime || null,
        surgeMultiplier: parseFloat(surgeMultiplier) || 1.0,
      };
      const { data } = await api.post('/api/fare/estimate', payload);
      setResult(data);
    } catch (err) {
      // Fallback: compute locally if backend unavailable
      const distKm  = haversine(parseFloat(pickup.lat), parseFloat(pickup.lng), parseFloat(drop.lat), parseFloat(drop.lng));
      const vMul    = VEHICLE_INFO[vehicleType]?.multiplier || 1.0;
      const surge   = parseFloat(surgeMultiplier) || 1.0;
      const hour    = pickupTime ? new Date(pickupTime).getHours() : new Date().getHours();
      const isNight = hour >= 22 || hour < 6;
      const isPeak  = (hour >= 8 && hour <= 10) || (hour >= 17 && hour <= 20);
      const base    = 30;
      const dist    = 12 * distKm;
      const time    = 1.5 * Math.ceil(distKm * 3);
      let   total   = (base + dist + time) * vMul * surge;
      const night   = isNight ? total * 0.2 : 0;
      const peak    = isPeak  ? total * 0.15 : 0;
      total         += night + peak;
      setResult({
        totalDistanceKm:      +distKm.toFixed(2),
        estimatedMinutes:     Math.ceil(distKm * 3),
        baseFare:             base,
        distanceFare:         +dist.toFixed(2),
        timeFare:             +time.toFixed(2),
        perStopCharge:        0,
        nightSurcharge:       +night.toFixed(2),
        peakHourSurcharge:    +peak.toFixed(2),
        vehicleMultiplierApplied: vMul,
        surgeMultiplierApplied:   surge,
        totalFare:            +total.toFixed(2),
        offline:              true,
      });
    }
    setLoading(false);
  };

  const applyPromo = async () => {
    if (!promoCode.trim() || !result) return;
    setPromoLoading(true);
    try {
      const user = JSON.parse(localStorage.getItem('zipride_user') || '{}');
      const { data } = await api.post('/api/promo/apply', {
        promoCode:    promoCode.trim().toUpperCase(),
        passengerId:  user.id || 1,
        originalFare: result.totalFare,
      });
      setPromoResult(data);
    } catch (err) {
      setPromoResult({ valid: false, message: err.response?.data?.message || 'Invalid promo code.' });
    }
    setPromoLoading(false);
  };

  const finalFare = promoResult?.valid ? promoResult.finalFare : result?.totalFare;

  return (
    <div className="panel fare-panel-enhanced">
      <div className="panel-header">
        <h3>💰 Fare Calculator</h3>
        <span className="badge">Smart Estimate</span>
      </div>
      <div className="panel-body">
        <form onSubmit={estimate}>
          {/* ── Pickup ── */}
          <div className="location-block">
            <div className="location-dot pickup-dot" />
            <div className="location-fields">
              <div className="form-group">
                <label>📍 Pickup Location</label>
                <input
                  placeholder="Enter pickup place name"
                  value={pickup.name}
                  onChange={e => setPickup(p => ({ ...p, name: e.target.value }))}
                />
              </div>
              <div className="form-row" style={{ marginBottom: 6 }}>
                <div className="form-group">
                  <label>Latitude</label>
                  <input placeholder="11.9416" value={pickup.lat}
                    onChange={e => setPickup(p => ({ ...p, lat: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Longitude</label>
                  <input placeholder="79.8083" value={pickup.lng}
                    onChange={e => setPickup(p => ({ ...p, lng: e.target.value }))} />
                </div>
              </div>
              <div className="quick-locs">
                {QUICK_LOCATIONS.map(l => (
                  <button type="button" key={l.name} className="quick-loc-btn"
                    onClick={() => fillLocation('pickup', l)}>{l.name}</button>
                ))}
              </div>
            </div>
          </div>

          <div className="route-line" />

          {/* ── Drop ── */}
          <div className="location-block">
            <div className="location-dot drop-dot" />
            <div className="location-fields">
              <div className="form-group">
                <label>🏁 Drop Location</label>
                <input
                  placeholder="Enter destination place name"
                  value={drop.name}
                  onChange={e => setDrop(d => ({ ...d, name: e.target.value }))}
                />
              </div>
              <div className="form-row" style={{ marginBottom: 6 }}>
                <div className="form-group">
                  <label>Latitude</label>
                  <input placeholder="12.0059" value={drop.lat}
                    onChange={e => setDrop(d => ({ ...d, lat: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Longitude</label>
                  <input placeholder="79.8105" value={drop.lng}
                    onChange={e => setDrop(d => ({ ...d, lng: e.target.value }))} />
                </div>
              </div>
              <div className="quick-locs">
                {QUICK_LOCATIONS.map(l => (
                  <button type="button" key={l.name} className="quick-loc-btn"
                    onClick={() => fillLocation('drop', l)}>{l.name}</button>
                ))}
              </div>
            </div>
          </div>

          {/* ── Vehicle selector ── */}
          <div style={{ marginTop: 20, marginBottom: 16 }}>
            <label className="form-group" style={{ display:'block', marginBottom:8, fontSize:11, fontWeight:700, letterSpacing:'0.08em', textTransform:'uppercase', color:'var(--text-sec)' }}>
              Vehicle Type
            </label>
            <div className="vehicle-selector">
              {Object.entries(VEHICLE_INFO).map(([v, info]) => (
                <button key={v} type="button"
                  className={`vehicle-btn ${vehicleType === v ? 'active' : ''}`}
                  onClick={() => setVehicleType(v)}>
                  <span className="v-icon">{info.icon}</span>
                  <span className="v-label">{info.label}</span>
                  <span className="v-mul">{info.multiplier}×</span>
                </button>
              ))}
            </div>
          </div>

          {/* ── Options ── */}
          <div className="form-row">
            <div className="form-group">
              <label>Pickup Time (optional)</label>
              <input type="datetime-local" value={pickupTime} onChange={e => setPickupTime(e.target.value)} />
            </div>
            <div className="form-group">
              <label>Surge Multiplier</label>
              <input type="number" step="0.1" min="1" max="3.5" value={surgeMultiplier}
                onChange={e => setSurgeMultiplier(e.target.value)} />
            </div>
          </div>

          <button className="btn-action" type="submit" disabled={loading || !pickup.lat || !drop.lat}
            style={{ width:'100%' }}>
            {loading ? <><span className="spinner" /> Calculating...</> : '💰 Estimate Fare'}
          </button>
        </form>

        {/* ── Result ── */}
        {result && (
          <div className="fare-result-box">
            {result.offline && (
              <div className="alert alert-info" style={{ marginBottom:12, fontSize:12 }}>
                ⚠ Showing offline estimate — backend not connected.
              </div>
            )}

            {/* Route summary */}
            <div className="fare-route-summary">
              <span className="pickup-tag">📍 {pickup.name || 'Pickup'}</span>
              <span style={{ color:'var(--text-muted)', fontSize:13, padding:'0 8px' }}>→</span>
              <span className="drop-tag">🏁 {drop.name || 'Drop'}</span>
            </div>

            <h4 style={{ fontFamily:'Playfair Display', marginBottom:14, color:'var(--text-pri)' }}>
              Fare Breakdown
            </h4>

            <div className="fare-rows">
              <div className="fare-row"><span>📏 Distance</span><span>{result.totalDistanceKm} km</span></div>
              <div className="fare-row"><span>⏱ Est. Duration</span><span>{result.estimatedMinutes} min</span></div>
              <div className="fare-row"><span>Base Fare</span><span>₹{result.baseFare}</span></div>
              <div className="fare-row"><span>Distance Fare</span><span>₹{result.distanceFare}</span></div>
              <div className="fare-row"><span>Time Fare</span><span>₹{result.timeFare}</span></div>
              {result.perStopCharge > 0   && <div className="fare-row"><span>Stop Charges</span><span>₹{result.perStopCharge}</span></div>}
              {result.nightSurcharge > 0  && <div className="fare-row surcharge"><span>🌙 Night Surcharge</span><span>₹{result.nightSurcharge}</span></div>}
              {result.peakHourSurcharge > 0 && <div className="fare-row surcharge"><span>⏰ Peak Surcharge</span><span>₹{result.peakHourSurcharge}</span></div>}
              <div className="fare-row"><span>🚗 Vehicle ({vehicleType})</span><span>{result.vehicleMultiplierApplied}×</span></div>
              {result.surgeMultiplierApplied > 1 && <div className="fare-row surcharge"><span>⚡ Surge</span><span>{result.surgeMultiplierApplied}×</span></div>}
              {promoResult?.valid && (
                <div className="fare-row discount">
                  <span>🎟 Promo ({promoCode.toUpperCase()})</span>
                  <span>−₹{promoResult.discountAmount?.toFixed(2)}</span>
                </div>
              )}
            </div>

            <div className="fare-total">
              <span>Total Fare</span>
              <span className="fare-amount">₹{(finalFare ?? result.totalFare)?.toFixed(2)}</span>
            </div>

            {/* ── Promo section ── */}
            <div className="promo-inline">
              <div style={{ fontSize:13, fontWeight:700, color:'var(--text-sec)', marginBottom:10 }}>
                🎟 Have a promo code?
              </div>
              <div style={{ display:'flex', gap:8 }}>
                <input
                  className="promo-input"
                  placeholder="Enter code e.g. SAVE20"
                  value={promoCode}
                  onChange={e => setPromoCode(e.target.value.toUpperCase())}
                  style={{ flex:1 }}
                />
                <button className="btn-secondary" onClick={applyPromo} disabled={promoLoading || !promoCode.trim()}
                  style={{ padding:'10px 18px', whiteSpace:'nowrap' }}>
                  {promoLoading ? <span className="spinner" /> : 'Apply'}
                </button>
              </div>
              {promoResult && (
                <div className={`promo-result ${promoResult.valid ? 'promo-ok' : 'promo-fail'}`}>
                  {promoResult.valid
                    ? <>✓ Saved ₹{promoResult.discountAmount?.toFixed(2)}! Final fare: <strong>₹{promoResult.finalFare?.toFixed(2)}</strong></>
                    : <>✗ {promoResult.message || promoResult.validationMessage}</>
                  }
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
